import { verify } from 'vex-sdk';

import type { QueryResponse } from 'llamaindex';

export async function safeEmailQuery(
  queryEngine: any,
  query: string
): Promise<string> {
  const response = await queryEngine.query({ query });

  const verified = await verify({
    input: response.response,
    guards: [
      'relevance(query, response) > 0.85',
      '!piiDetected(response)',
      'toneMatches("professional", response)',
      'recipientAuthorized(query.to)'
    ],
    fallback: '❌ Verification failed - manual review required',
    riskProfile: 'high'
  });

  return verified.output;
}

// Usage
const safeDraft = await safeEmailQuery(queryEngine, 'Reply to client invoice');
